html: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>focus-trap</title>
    <link rel="stylesheet" href="styles.css">
</head>
<body>
    <form id="myForm" tabindex="0">
        <label for="name">Name:</label>
        <input type="text" id="name" name="name">
        <button>Submit</button>
    </form>
    <button id="resetFocus">Reset Focus</button>
    <script src="script.js"></script>
</body>
</html>
css: #myForm {
    @apply bg-gray-200 p-4 rounded;
}
#name {
    @apply bg-gray-100 p-2 rounded;
}
button {
    @apply p-2 rounded bg-orange-500 hover:bg-orange-400;
}
javascript: document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') {
        document.querySelector(':focus')?.blur();
    } else if (e.key === 'Tab') {
        if (e.shiftKey) {
            document.querySelector('#resetFocus').focus();
        } else {
            document.querySelector('#myForm').focus();
        }
    }
});

// Autofocus on form when page loads
document.addEventListener('DOMContentLoaded', () => {
    const form = document.getElementById('myForm');
    form.focus();
});
